#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}
int main() {
    int n;
    scanf("%d", &n);
    int segments[n][2];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &segments[i][0], &segments[i][1]);
    }
    qsort(segments, n, sizeof(segments[0]), compare);
    int points = 1;
    int last = segments[0][1];
    for (int i = 1; i < n; i++) {
        if (segments[i][0] > last) {
            points++;
            last = segments[i][1];
        }
    }
    printf("%d\n", points);
    return 0;
}

