#include <iostream>
#include <algorithm>
using namespace std;
bool compare(int a[], int b[]) {
    return a[1] < b[1];
}
int main() {
    int n;
    cin >> n;
    int segments[n][2];
    for (int i = 0; i < n; i++) {
        cin >> segments[i][0] >> segments[i][1];
    }
    sort(segments, segments + n, compare);
    int points = 1;
    int last = segments[0][1];
    for (int i = 1; i < n; i++) {
        if (segments[i][0] > last) {
            points++;
            last = segments[i][1];
        }
    }
    cout << points << endl;
    return 0;
}

