const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let n = +lines[0];
    let segments = lines.slice(1).map((line) => line.split(' ').map(Number));
    segments.sort((a, b) => a[1] - b[1]);
    let points = 1;
    let last = segments[0][1];
    for (let i = 1; i < n; i++) {
        if (segments[i][0] > last) {
            points++;
            last = segments[i][1];
        }
    }
    console.log(points);
});
